export declare const skyVertex = "\nvarying vec2 vUv;\nvoid main() {\n  vUv = uv;\n  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);\n}\n";
export declare const skyFragment = "\nvarying vec2 vUv;\n\nuniform float uTime;\nuniform vec3 uTop;\nuniform vec3 uBottom;\nuniform vec2 uSun;\nuniform vec3 uSunColor;\nuniform float uHaze;\nuniform float uNoise;\n\n// cheap hash noise\nfloat hash(vec2 p){\n  p = fract(p * vec2(123.34, 456.21));\n  p += dot(p, p + 34.345);\n  return fract(p.x * p.y);\n}\nfloat noise(vec2 p){\n  vec2 i = floor(p);\n  vec2 f = fract(p);\n  float a = hash(i);\n  float b = hash(i + vec2(1.0, 0.0));\n  float c = hash(i + vec2(0.0, 1.0));\n  float d = hash(i + vec2(1.0, 1.0));\n  vec2 u = f*f*(3.0-2.0*f);\n  return mix(a, b, u.x) + (c - a)*u.y*(1.0-u.x) + (d - b)*u.x*u.y;\n}\n\nvoid main() {\n  float y = clamp(vUv.y, 0.0, 1.0);\n  vec3 col = mix(uBottom, uTop, smoothstep(0.0, 1.0, y));\n\n  // sun glow (radial)\n  float d = distance(vUv, uSun);\n  float sunCore = exp(-d * 10.0);\n  float sunGlow = exp(-d * 3.0);\n  col += uSunColor * (sunCore * 0.35 + sunGlow * 0.18);\n\n  // horizon haze band\n  float hazeBand = exp(-pow((vUv.y - 0.32) / 0.12, 2.0)) * uHaze;\n  col = mix(col, uSunColor, hazeBand * 0.35);\n\n  // painterly noise (subtle)\n  vec2 nUv = vUv * vec2(6.0, 3.0);\n  nUv += vec2(uTime * 0.01, -uTime * 0.006);\n  float n = noise(nUv) - 0.5;\n  col += n * uNoise;\n\n  gl_FragColor = vec4(col, 1.0);\n}\n";
